import React, {useEffect, useState} from 'react'
import styled from 'styled-components'
import {getTrendingItems} from '../WebAPI'
import {parseISO, formatDistanceToNow} from 'date-fns'
import {Link} from 'react-router-dom'


const TrendingSectionWrapper = styled.div `
width:90%;
margin:60px auto;

`

const Title = styled.div `
font-size:1.5rem;
font-weight:bold;
`
const ImageWrapper = styled.div `
margin-top:20px;
display:flex;
justify-content:space-between;
align-items:center;
`

const Image = styled.div `
background-image:url(${props => props.image && props.image});
width:100%;
height:300px;
background-size:contain;
background-position:center;
background-repeat:no-repeat;
`
const ListDate = styled.div `
font-size:0.6rem;
color:grey;
margin:5px 0px;
`

const ImageCard = styled(Link) `
width:15vw;
font-size:0.7rem;
color:#1C1C1C;
text-decoration:none;
&:hover {
	cursor:pointer;
}
`

const HeaderWrapper = styled.div `
width:100%;
display:flex;
justify-content:space-between;
align-items:center;
`

const ListTitle = styled.div `
font-size:0.9rem;
white-space: nowrap;
text-overflow:ellipsis;
width:90%;
overflow:hidden;
`

const ListSize = styled.div ``

const ListContent = styled.div `
text-overflow:ellipsis;
font-size:0.7rem;
overflow:hidden;
margin:5px 0px;
white-space: nowrap;
`

const FooterWrapper = styled.div `
display:flex;
justify-content:space-between;
`

const Price = styled.div ``

const Like = styled.div ``

export default function Trending () {
	const [trendingItems, setTrendingItems] = useState([{}])

	useEffect(() => {
		getTrendingItems(setTrendingItems)
	}, [])


	return (
		<TrendingSectionWrapper>
			<Title>Trending Items</Title>
			<ImageWrapper>
				{trendingItems.map(item => 
					<ImageCard key={`${item.id}:${item.index}`} to={`/shop/listing/${item.id}`}>
						<Image image={item.image_1}/>
						<ListDate>{item.createdAt ? formatDistanceToNow(parseISO(item.createdAt)) : null}</ListDate>
						<HeaderWrapper>
							<ListTitle>{item.itemName}</ListTitle>
							<ListSize>{item.Size ? item.Size.name : null}</ListSize>
						</HeaderWrapper>
						<ListContent>{item.description}</ListContent>
						<FooterWrapper>
							<Price></Price>
							<Like />
						</FooterWrapper>
					</ImageCard>
				)}
			</ImageWrapper>
		</TrendingSectionWrapper>
	)
}
